#include<bits/stdc++.h>
using namespace std;
#define int long long

const int N = 1e5 + 5;

int n, m, s;

struct Edge
{
    int v, w;
};
vector<Edge> e1[N], e2[N];

int dis1[N], dis2[N];
bool vis[N];

void Dijkstra1()
{
    memset(dis1, 0x3f, sizeof dis1);
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> q;
    q.push({0, s});
    dis1[s] = 0;
    while(!q.empty())
    {
        auto [d, u] = q.top();
        q.pop();
        if(vis[u]) continue;
        vis[u] = 1;
        for(auto [v, w] : e1[u])
        {
            if(dis1[v] > dis1[u] + w)
            {
                dis1[v] = dis1[u] + w;
                q.push({dis1[v], v});
            }
        }
    }
}

void Dijkstra2()
{
    memset(dis2, 0x3f, sizeof dis2);
    memset(vis, 0, sizeof vis);
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> q;
    q.push({0, s});
    dis2[s] = 0;
    while(!q.empty())
    {
        auto [d, u] = q.top();
        q.pop();
        if(vis[u]) continue;
        vis[u] = 1;
        for(auto [v, w] : e2[u])
        {
            if(dis2[v] > dis2[u] + w)
            {
                dis2[v] = dis2[u] + w;
                q.push({dis2[v], v});
            }
        }
    }
}

signed main()
{
    cin.tie(0) -> sync_with_stdio(0);
    cin >> n >> m;
    s = 1;
    for(int i = 1; i <= m; i++)
    {
        int u, v, w;
        cin >> u >> v >> w;
        e1[u].push_back({v, w});
        e2[v].push_back({u, w});
    }
    Dijkstra1();
    Dijkstra2();
    int ans = 0;
    for(int i = 1; i <= n; i++)
        ans += dis1[i] + dis2[i];
    cout << ans;
    return 0;
}
